script:
frappe.after_ajax(() => {
    setTimeout(() => {
        bind_number_card_clicks();
        apply_number_card_colors(); 
    }, 600);
});

let __cached_table_data = null;
let __active_card_name = null;

const cardColorMap = {
    "Cash Balance": "orange",
    "Bank Balance": "red",
    "Open Quotation": "green",
    "Customer To Delivery": "grey"
};

function bind_number_card_clicks() {
    const blocks = document.querySelectorAll('.ce-block div[number_card_name]');
    const tableRoot = root_element.querySelector('#number-card-table-root');
    if (!tableRoot) return;

    if (!tableRoot.querySelector(".table-container")) {
        const div = document.createElement("div");
        div.className = "table-container";
        tableRoot.appendChild(div);
    }

    blocks.forEach(wrapper => {
        const cardName = wrapper.getAttribute("number_card_name");
        if (!cardName) return;

        const ceBlock = wrapper.closest(".ce-block");
        if (!ceBlock) return;

        ceBlock.style.cursor = "pointer";

        const widget = wrapper.querySelector('.number-widget-box');
        if (!widget) return;

        widget.addEventListener("mousedown", e => e.stopImmediatePropagation(), true);

        widget.addEventListener("click", e => {
            e.preventDefault();
            e.stopImmediatePropagation();
            load_number_card_table(cardName, tableRoot);
        }, true);
    });
}

function load_number_card_table(cardName, tableRoot) {
    __active_card_name = cardName;

    const tableContainer = tableRoot.querySelector(".table-container");
    tableContainer.innerHTML = `<p class="text-muted">Loading ${cardName}…</p>`;

    // Handle Customer To Delivery differently - query Sales Orders directly
    if (cardName === "Customer To Delivery") {
        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Sales Order",
                filters: {
                    "docstatus": 1,
                    "status": ["in", ["To Deliver", "To Deliver and Bill", "To Bill"]]
                },
                fields: ["name", "customer", "customer_name", "transaction_date", "delivery_date", "grand_total", "status", "per_delivered"],
                order_by: "delivery_date asc, transaction_date asc",
                limit_page_length: 1000
            },
            callback: r => {
                if (!r.message || !r.message.length) {
                    tableContainer.innerHTML = `<p class="text-muted">No data</p>`;
                    return;
                }

                // Format the data for the table
                const company = frappe.defaults.get_user_default("Company");
                frappe.db.get_value("Company", company, "default_currency").then(currency_result => {
                    const currency = currency_result ? currency_result.default_currency : "";
                    const formattedData = r.message.map(so => ({
                        "Sales Order ID": so.name,
                        "Customer": so.customer_name || so.customer,
                        "Order Date": so.transaction_date || "",
                        "Delivery Date": so.delivery_date || "",
                        "Amount": frappe.format(so.grand_total, { fieldtype: "Currency", currency: currency }),
                        "Status": so.status,
                        "Delivered %": (so.per_delivered || 0) + "%"
                    }));

                    __cached_table_data = formattedData;
                    inject_filters(tableRoot);
                    render_table(tableRoot, formattedData, cardName);
                    bind_sales_order_links(tableRoot);
                });


            }
        });
        return;
    }

    // Handle Cash Balance
    if (cardName === "Cash Balance") {
        frappe.call({
            method: "nextlayer.next_layer.number_card.cash_balance.get_cash_balance.get_balance",
            callback: r => {
                if (!r.message || !r.message.length) {
                    tableContainer.innerHTML = `<p class="text-muted">No data</p>`;
                    return;
                }
                // Format balance values
                const formattedData = r.message.map(acc => ({
                    "Account": acc.Account || acc["Account Type"] || "",
                    "Balance": frappe.format(acc.Balance || acc["Total Balance"] || 0, { fieldtype: "Currency" })
                }));
                __cached_table_data = formattedData;
                inject_filters(tableRoot);
                render_table(tableRoot, formattedData, cardName);
            }
        });
        return;
    }

    // Handle Bank Balance
    if (cardName === "Bank Balance") {
        frappe.call({
            method: "nextlayer.next_layer.number_card.bank_balance_1.get_bank_balance.get_balance",
            callback: r => {
                if (!r.message || !r.message.length) {
                    tableContainer.innerHTML = `<p class="text-muted">No data</p>`;
                    return;
                }
                // Format balance values
                const formattedData = r.message.map(acc => ({
                    "Account": acc.Account || acc["Account Type"] || "",
                    "Balance": frappe.format(acc.Balance || acc["Total Balance"] || 0, { fieldtype: "Currency" })
                }));
                __cached_table_data = formattedData;
                inject_filters(tableRoot);
                render_table(tableRoot, formattedData, cardName);
            }
        });
        return;
    }

    if (cardName === "Open Quotation") {
        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Quotation",
                filters: {
                    "docstatus": 1,
                    "status": "Open"
                },
                fields: ["name", "party_name", "customer_name", "transaction_date", "valid_till", "grand_total", "status"],
                order_by: "transaction_date desc",
                limit_page_length: 1000
            },
            callback: r => {
                if (!r.message || !r.message.length) {
                    tableContainer.innerHTML = `<p class="text-muted">No data</p>`;
                    return;
                }
                // Format the data for the table
                const company = frappe.defaults.get_user_default("Company");
                frappe.db.get_value("Company", company, "default_currency").then(currency_result => {
                    const currency = currency_result ? currency_result.default_currency : "";
                    const formattedData = r.message.map(q => ({
                        "Quotation ID": q.name,
                        "Customer": q.customer_name || q.party_name || "",
                        "Date": q.transaction_date || "",
                        "Valid Till": q.valid_till || "",
                        "Amount": frappe.format(q.grand_total, { fieldtype: "Currency", currency: currency }),
                        "Status": q.status
                    }));
                    __cached_table_data = formattedData;
                    inject_filters(tableRoot);
                    render_table(tableRoot, formattedData, cardName);
                });
            }
        });
        return;
    }

    tableContainer.innerHTML = `<p class="text-muted">No API mapped for ${cardName}</p>`;
}

/* Table renderer with cleaner style */
function render_table(tableRoot, data, cardName) {
    const tableContainer = tableRoot.querySelector(".table-container");

    if (!data.length) {
        tableContainer.innerHTML = `<p class="text-muted">No matching results</p>`;
        return;
    }

    const dataColumns = Object.keys(data[0]);
    const columns = ["#", ...dataColumns];

    const thColor = cardColorMap[cardName] || "#ddd";

    const thead = `
        <thead>
            <tr>
                ${columns.map(c => `<th style="background-color:${thColor}; color:white;">${c}</th>`).join("")}
            </tr>
        </thead>
    `;

    const tbody = `
        <tbody>
            ${data.map((row, idx) => `
                <tr>
                    <td>${idx + 1}</td>
                    ${dataColumns.map(c => {
                        if (cardName === "Customer To Delivery" && c === "Sales Order ID") {
                            return `<td><a href="#" class="so-link" data-so="${row[c]}">${row[c]}</a></td>`;
                        }
                        return `<td>${row[c] ?? ""}</td>`;
                    }).join("")}
                </tr>
            `).join("")}
        </tbody>
    `;

    tableContainer.innerHTML = `<table class="table table-sm table-striped">${thead}${tbody}</table>`;
}

/* Filter UI and logic: only for Customer To Delivery */
function inject_filters(tableRoot) {
    let filterBar = tableRoot.querySelector(".filter-bar");

    if (!filterBar) {
        filterBar = document.createElement("div");
        filterBar.className = "filter-bar mb-2 gap-2";
        filterBar.innerHTML = `
            <input type="text" class="form-control form-control-sm" placeholder="Search Customer" data-filter="customer">
            <input type="text" class="form-control form-control-sm ms-3" placeholder="Search Sales Order ID" data-filter="sales_order">
        `;
        tableRoot.prepend(filterBar);

        const keyMap = { customer: "Customer", sales_order: "Sales Order ID" };

        filterBar.querySelectorAll("input").forEach(input => {
            input.addEventListener("input", e => {
                e.stopImmediatePropagation();
                apply_filters(tableRoot, keyMap);
            });
            ["keydown", "keypress", "keyup", "mousedown", "focus"].forEach(evt =>
                input.addEventListener(evt, e => e.stopImmediatePropagation(), true)
            );
        });
    }
    console.log(__active_card_name)
    // Show only if Customer To Delivery
    // filterBar.style.display = (__active_card_name === "Customer To Delivery") ? "flex" : "none !important";
    if (__active_card_name === "Customer To Delivery"){
        filterBar.style.display = "flex"
    }else {
        filterBar.style.display = "none"
    }
}


function apply_filters(tableRoot, keyMap) {
    if (!__cached_table_data) return;

    const inputs = tableRoot.querySelectorAll(".filter-bar input");
    let filtered = [...__cached_table_data];

    inputs.forEach(input => {
        const key = keyMap[input.dataset.filter];
        const value = input.value.toLowerCase();
        if (!value) return;

        filtered = filtered.filter(row =>
            String(row[key] || "").toLowerCase().includes(value)
        );
    });

    render_table(tableRoot, filtered, __active_card_name);
    bind_sales_order_links(tableRoot);
}

/* Sales Order → Invoice */
function bind_sales_order_links(tableRoot) {
    tableRoot.querySelectorAll(".so-link").forEach(link => {
        link.addEventListener("click", e => {
            e.preventDefault();
            e.stopImmediatePropagation();
            const so = link.dataset.so;

            frappe.model.open_mapped_doc({
                method: "erpnext.selling.doctype.sales_order.sales_order.make_sales_invoice",
                source_name: so
            });
        });
    });
}

/* Number card colors */
function apply_number_card_colors() {
    const cards = document.querySelectorAll('div[number_card_name]');
    cards.forEach(card => {
        const cardName = card.getAttribute("number_card_name");
        const color = cardColorMap[cardName];
        if (!color) return;

        if (card.querySelector(".number-card-color-bar")) return;

        const bar = document.createElement("div");
        bar.className = "number-card-color-bar";
        Object.assign(bar.style, {
            position: "absolute",
            left: "0",
            top: "0",
            width: "4%",
            height: "100%",
            backgroundColor: color,
            borderRadius: "12px 0 0 12px",
            zIndex: "10"
        });

        const widgetBox = card.querySelector(".number-widget-box");
        if (widgetBox) {
            widgetBox.style.position = "relative";
            widgetBox.prepend(bar);
        }
    });
}

style:
#number-card-table-root {
    margin-top: 12px;
}

#number-card-table-root table {
    width: 100%;
    border-collapse: collapse;
}

#number-card-table-root th,
#number-card-table-root td {
    padding: 6px 10px;
}

#number-card-table-root th {
    font-weight: bold;
}

#number-card-table-root td {
    border-bottom: 1px solid #eee;
}

#number-card-table-root tbody tr:hover {
    background-color: rgba(0,0,0,0.03);
}

.form-control {
    margin-right: 10px;
}
